import { defineCustomElements as deckDeckGoHighlightElement } from '@deckdeckgo/highlight-code/dist/loader';
import { graphql } from 'gatsby';
import { MDXRenderer } from 'gatsby-plugin-mdx';
import React from 'react';
import { Helmet } from 'react-helmet';
import styled from 'styled-components';
import Container from '../../components/atoms/Container';
import BlogHeader from '../../components/molecules/BlogHeader';
import BlogTitle from '../../components/molecules/BlogTitle';

deckDeckGoHighlightElement();

const StyledMDX = styled.div`
  padding-top: 2rem;

  h3,
  h4,
  ol,
  ul {
    margin-bottom: 2rem;
  }

  h3 {
    font-size: 1.5rem;
    line-height: 2rem;
  }

  h4 {
    font-size: 1.25rem;
    line-height: 1.75rem;
  }

  ol,
  ul {
    list-style-position: inside;
  }

  ul {
    list-style-type: disc;
  }

  ol {
    list-style-type: decimal;
  }

  p {
    margin-bottom: 2rem;
  }
`;

export type BlogPageProps = {
  data: {
    mdx: {
      body: string;
      frontmatter: { title: string; description: string; date: string };
    };
  };
};

const BlogPage: React.FC<BlogPageProps> = ({ data }) => {
  return (
    <>
      <Helmet>
        <title>HIEU: {data.mdx.frontmatter.title}</title>
      </Helmet>
      <BlogHeader />
      <BlogTitle
        title={data.mdx.frontmatter.title}
        description={data.mdx.frontmatter.description}
        date={data.mdx.frontmatter.date}
      />
      <Container>
        <StyledMDX>
          <MDXRenderer>{data.mdx.body}</MDXRenderer>
        </StyledMDX>
      </Container>
    </>
  );
};

export const query = graphql`
  query ($id: String) {
    mdx(id: { eq: $id }) {
      frontmatter {
        title
        date(formatString: "MMMM D, YYYY")
        author
        description
      }
      body
    }
  }
`;

export default BlogPage;
